sql:
SELECT COUNT(DISTINCT ja.user_id) AS unique_users_with_qualifications
FROM job_applications ja
JOIN user_qualifications uq ON ja.user_id = uq.user_id;

SELECT jl.job_title, o.org_name
FROM job_listings jl
INNER JOIN organizations o ON jl.org_id = o.org_id;

SELECT company_size, COUNT(org_id) AS number_of_organizations
FROM organizations
GROUP BY company_size;

SELECT COUNT(job_id) AS number_of_full_time_jobs
FROM job_listings
WHERE job_type = 'Full-time';

external_knowledge:
- "finance companies" refers to organizations in the finance industry; 
- "more than one full-time job" indicates that there are at least two full-time positions listed; 
- "minimum of 3 years experience" is the lowest threshold set for the job requirements.

